/**
 * Video Service - Handles all video API operations
 */

import api from './api';

export const videoService = {
    /**
     * Get all videos
     * @param {boolean} activeOnly - Get only active videos (default: true)
     */
    getAll: async (activeOnly = true) => {
        const response = await api.get(`/videos?activeOnly=${activeOnly}`);
        return response.data;
    },
    
    /**
     * Get currently active video for TV display
     */
    getActiveVideo: async () => {
        const response = await api.get('/videos/active');
        return response.data;
    },
    
    /**
     * Create new video (Super Admin only)
     */
    create: async (videoData) => {
        const response = await api.post('/videos', videoData);
        return response.data;
    },
    
    /**
     * Update existing video (Super Admin only)
     */
    update: async (id, videoData) => {
        const response = await api.put(`/videos/${id}`, videoData);
        return response.data;
    },
    
    /**
     * Delete video (Super Admin only)
     */
    delete: async (id) => {
        const response = await api.delete(`/videos/${id}`);
        return response.data;
    },
    
    /**
     * Toggle video active status
     */
    toggleStatus: async (id, status) => {
        const response = await api.put(`/videos/${id}`, { status });
        return response.data;
    }
};

export default videoService;