/**
 * API Client - Configured Axios instance with authentication interceptors
 */

import axios from 'axios';
import { authService } from './authService';

const API_URL = process.env.REACT_APP_API_URL || 'http://localhost:5000/api';

// Create axios instance with default config
const api = axios.create({
    baseURL: API_URL,
    timeout: 30000,
    headers: {
        'Content-Type': 'application/json',
    }
});

// Request interceptor - Automatically add JWT token to all requests
api.interceptors.request.use(
    (config) => {
        const token = authService.getToken();
        if (token) {
            config.headers.Authorization = `Bearer ${token}`;
        }
        return config;
    },
    (error) => Promise.reject(error)
);

// Response interceptor - Handle token refresh on 401 errors + User-friendly messages
api.interceptors.response.use(
    (response) => response,
    async (error) => {
        const originalRequest = error.config;
        
        // Handle 401 Unauthorized - Attempt token refresh
        if (error.response?.status === 401 && !originalRequest._retry) {
            originalRequest._retry = true;
            
            try {
                const newToken = await authService.refreshToken();
                originalRequest.headers.Authorization = `Bearer ${newToken}`;
                return api(originalRequest);
            } catch (refreshError) {
                // Refresh failed - logout and redirect to login
                authService.logout();
                window.location.href = '/admin/login';
                return Promise.reject(refreshError);
            }
        }
        
        // User-friendly error messages
        let userMessage = 'An unexpected error occurred';
        const status = error.response?.status;
        
        if (status === 400) userMessage = 'Invalid request. Please check your input.';
        else if (status === 401) userMessage = 'Authentication failed. Please login again.';
        else if (status === 403) userMessage = 'You do not have permission to perform this action.';
        else if (status === 404) userMessage = 'Resource not found.';
        else if (status === 409) userMessage = 'Resource conflict. It may already exist.';
        else if (status === 422) userMessage = 'Validation failed. Please check your data.';
        else if (status === 500) userMessage = 'Server error. Please try again later.';
        else if (!error.response) userMessage = 'Network error. Please check your connection.';
        
        const errorResponse = {
            success: false,
            message: userMessage,
            technicalMessage: error.response?.data?.message,
            status: status,
            data: error.response?.data
        };
        
        // Trigger toast notification if NotificationContext available
        if (typeof window !== 'undefined' && window.showToast) {
            window.showToast(userMessage, 'error');
        }
        
        return Promise.reject(errorResponse);
    }
);

export default api;